UPDATE STOCTCCT
   SET MOD_DATE     = ${systemDateTime}
     , MOD_USER_ID  = #{ses.userId}
     , SEND_YN = #{SEND_YN}
 WHERE GATE_CD  = #{ses.gateCd}
   AND BUYER_CD = #{BUYER_CD}
   AND CONT_NUM = #{CONT_NUM}
   AND CONT_CNT = #{CONT_CNT}
   AND USER_ID = #{USER_ID}

mapper.select:
        SELECT (CASE WHEN PROGRESS_CD = '4300' THEN 'N' ELSE 'Y' END) 
          FROM STOCTCCT 
         WHERE GATE_CD  = #{ses.gateCd}
		   AND BUYER_CD = #{BUYER_CD}
		   AND CONT_NUM = #{CONT_NUM}
		   AND CONT_CNT = #{CONT_CNT}
		   AND USER_ID = #{USER_ID}

